Question 5:
Compare run time between parLapply, foreach and replicate for the above problem.

time_replicate &lt;- system.time({
  res1 &lt;- replicate(3, max(rnorm(5)))
})

cl5 &lt;- makeCluster(3)
registerDoParallel(cl5)

time_parLapply &lt;- system.time({
  res2 &lt;- parLapply(cl5, 1:3, function(i){max(rnorm(5))})
  })

time_foreach &lt;- system.time({
  res3 &lt;- foreach(x = irnorm(count = 3, n = 5), .combine = c) %dopar% {
    max(x)
  }
})

stopCluster(cl5)


num_vectors &lt;- 1000
vector_size &lt;- 10000

time_replicate2 &lt;- system.time({
  res1 &lt;- replicate(num_vectors, max(rnorm(vector_size)))
})

cl6 &lt;- makeCluster(3)
registerDoParallel(cl6)

time_parLapply2 &lt;- system.time({
  res2 &lt;- parLapply(cl6, 1:num_vectors, function(i, sz) max(rnorm(sz)), sz = vector_size)
})

time_foreach2 &lt;- system.time({
  res3 &lt;- foreach(x = irnorm(count = num_vectors, n = vector_size), .combine = c) %dopar% {
    max(x)
  }
})

stopCluster(cl6)

results_table &lt;- data.frame(
  Method = c("replicate", "parLapply", "foreach"),
  'Time (3 vectors)' = c(time_replicate["elapsed"], time_parLapply["elapsed"], time_foreach["elapsed"]),
  'Time (1000 vectors)' = c(time_replicate2["elapsed"], 
                   time_parLapply2["elapsed"], 
                   time_foreach2["elapsed"]),
  check.names = FALSE
)
kable(results_table)




